#include <XSegment_lib.h>

XSeg_TM1638 display(2, 3, 4);

void setup() {
  Serial.begin(115200);
  display.begin();
  display.setBrightness(7);

  Serial.println("=== TM1638 Demo ===");
}

void loop() {
  static int counter = 0;

  // Show 8-digit integer
  display.show(counter);
  Serial.print("Display: "); Serial.println(counter);
  counter = (counter + 1) % 100000000;
  delay(200);

  // String display
  display.show("ARDUINO");
  Serial.println("Display: ARDUINO");
  delay(500);

  // Scroll test
  display.scroll("SCROLLING TEXT DEMO", 100);
  Serial.println("Scrolling...");
  delay(1000);
}
